"use client";

import type { Variants } from "motion/react";
import { motion, useAnimation } from "motion/react";
import type { HTMLAttributes } from "react";
import { forwardRef, useCallback, useImperativeHandle, useRef } from "react";
import { cn } from "@/lib/utils";

export interface PhoneForwardedIconHandle {
  startAnimation: () => void;
  stopAnimation: () => void;
}

interface PhoneForwardedIconProps extends HTMLAttributes<HTMLDivElement> {
  size?: number;
}

// Line: shrink then extend (like arrow-right)
const LINE_VARIANTS: Variants = {
  normal: { d: "M14 6h8" },
  animate: {
    d: ["M14 6h8", "M14 6h4", "M14 6h8"],
    transition: { duration: 0.4 },
  },
};

// Arrowhead: translateX for "shoot right" effect (like arrow-right)
const ARROWHEAD_VARIANTS: Variants = {
  normal: { translateX: 0 },
  animate: {
    translateX: [0, -3, 0],
    transition: { duration: 0.4 },
  },
};

const PhoneForwardedIcon = forwardRef<
  PhoneForwardedIconHandle,
  PhoneForwardedIconProps
>(
  ({ onMouseEnter, onMouseLeave, className, size = 28, ...props }, ref) => {
    const controls = useAnimation();
    const isControlledRef = useRef(false);

    useImperativeHandle(ref, () => {
      isControlledRef.current = true;
      return {
        startAnimation: () => controls.start("animate"),
        stopAnimation: () => controls.start("normal"),
      };
    });

    const handleMouseEnter = useCallback(
      (e: React.MouseEvent<HTMLDivElement>) => {
        if (isControlledRef.current) {
          onMouseEnter?.(e);
        } else {
          controls.start("animate");
        }
      },
      [controls, onMouseEnter]
    );

    const handleMouseLeave = useCallback(
      (e: React.MouseEvent<HTMLDivElement>) => {
        if (isControlledRef.current) {
          onMouseLeave?.(e);
        } else {
          controls.start("normal");
        }
      },
      [controls, onMouseLeave]
    );

    return (
      <div
        className={cn(className)}
        onMouseEnter={handleMouseEnter}
        onMouseLeave={handleMouseLeave}
        {...props}
        style={{ ...props.style, overflow: "visible" }}
      >
        <svg
          fill="none"
          height={size}
          preserveAspectRatio="xMidYMid meet"
          stroke="currentColor"
          strokeLinecap="round"
          strokeLinejoin="round"
          strokeWidth="2"
          style={{ overflow: "visible" }}
          viewBox="0 0 24 24"
          width={size}
          xmlns="http://www.w3.org/2000/svg"
        >
          <motion.path
            animate={controls}
            d="M14 6h8"
            variants={LINE_VARIANTS}
          />
          <motion.path
            animate={controls}
            d="m18 2 4 4-4 4"
            variants={ARROWHEAD_VARIANTS}
          />
          <path d="M13.832 16.568a1 1 0 0 0 1.213-.303l.355-.465A2 2 0 0 1 17 15h3a2 2 0 0 1 2 2v3a2 2 0 0 1-2 2A18 18 0 0 1 2 4a2 2 0 0 1 2-2h3a2 2 0 0 1 2 2v3a2 2 0 0 1-.8 1.6l-.468.351a1 1 0 0 0-.292 1.233 14 14 0 0 0 6.392 6.384" />
        </svg>
      </div>
    );
  }
);

PhoneForwardedIcon.displayName = "PhoneForwardedIcon";

export { PhoneForwardedIcon };
